mapper.insert:
/** UsptStdrRsltIdxDao.insert */
insert into uspt_stdr_rslt_idx
						(
							rslt_idx_id
							, stdr_bsns_cd
							, rslt_idx_nm
							, std_idx
							, rslt_idx_type_cd
							, creator_id
							, created_dt
							, updater_id
							, updated_dt
						)
				values	(
							#{rsltIdxId}
							, #{stdrBsnsCd}
							, #{rsltIdxNm}
							, #{stdIdx}
							, #{rsltIdxTypeCd}
							, #{creatorId}
							, #{createdDt}
							, #{updaterId}
							, #{updatedDt}
						)

mapper.update:
/** UsptStdrRsltIdxDao.update */
update uspt_stdr_rslt_idx
set
	updater_id		= #{updaterId}
	, updated_dt	= #{updatedDt}
	, std_idx		= #{stdIdx}
	, rslt_idx_nm	= #{rsltIdxNm}
where
	rslt_idx_id = #{rsltIdxId}
	and stdr_bsns_cd = #{stdrBsnsCd}

mapper.delete:
/** UsptStdrRsltIdxDao.delete */
delete from uspt_stdr_rslt_idx
where
	rslt_idx_id = #{rsltIdxId}
	and stdr_bsns_cd = #{stdrBsnsCd}
